import React, { useEffect, useState } from 'react';
import { Card, Table, Button, Badge, Row, Col, Alert } from 'react-bootstrap';
import { Clock, Bell, AlertCircle, CheckCircle, TrendingUp, RefreshCw, Filter, X } from 'lucide-react';
import { getExpiries, triggerExpiryNotifications } from '../api';
import { toast } from 'react-toastify';
import './ExpiryDashboard.css';

const ExpiryDashboard = () => {
  const [expiries, setExpiries] = useState([]);
  const [filteredExpiries, setFilteredExpiries] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activeFilter, setActiveFilter] = useState('all');
  const [stats, setStats] = useState({
    expired: 0,
    expiring5Days: 0,
    expiring30Days: 0,
    total: 0
  });

  const load = async () => {
    setLoading(true);
    try {
      const res = await getExpiries();
      if (res.data && res.data.data) {
        const expiryData = res.data.data;
        
        // Process and recalculate daysLeft to ensure accuracy
        const processedData = expiryData.map(item => {
          if (item.expiryDate) {
            const expiryStr = item.expiryDate;
            const expiry = new Date(expiryStr);
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            expiry.setHours(0, 0, 0, 0);
            const diffTime = expiry - today;
            const daysLeft = Math.floor(diffTime / (1000 * 60 * 60 * 24));
            return { ...item, daysLeft: Number(daysLeft) };
          }
          return { ...item, daysLeft: 999 };
        });
        
        setExpiries(processedData);
        
        // Apply current filter to new data
        applyFilter(activeFilter, processedData);
        
        // Calculate statistics
        // EXPIRED: Days <= 0 (Today and all past dates)
        const expiredDocs = processedData.filter(e => Number(e.daysLeft) <= 0);
        
        // EXPIRING SOON (Critical): Days 1-5
        const expiring5Docs = processedData.filter(e => Number(e.daysLeft) >= 1 && Number(e.daysLeft) <= 5);
        
        // EXPIRING SOON (Warning): Days 6-30
        const expiring30Docs = processedData.filter(e => Number(e.daysLeft) >= 6 && Number(e.daysLeft) <= 30);
        
        setStats({
          expired: expiredDocs.length,
          expiring5Days: expiring5Docs.length,
          expiring30Days: expiring30Docs.length,
          total: processedData.length
        });
      }
    } catch (err) {
      console.error(err);
      toast.error('Failed to load expiry data', {
        position: 'top-right',
        autoClose: 3000
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
    const interval = setInterval(load, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  const applyFilter = (filterType, data = expiries) => {
    switch(filterType) {
      case 'expired':
        // EXPIRED: Show only documents with days <= 0 (today and all past dates)
        setFilteredExpiries(data.filter(e => Number(e.daysLeft) <= 0));
        break;
      case 'expiring5':
        // EXPIRING CRITICAL: Show documents with days 1-5
        setFilteredExpiries(data.filter(e => Number(e.daysLeft) >= 1 && Number(e.daysLeft) <= 5));
        break;
      case 'expiring30':
        // EXPIRING WARNING: Show documents with days 6-30
        setFilteredExpiries(data.filter(e => Number(e.daysLeft) >= 6 && Number(e.daysLeft) <= 30));
        break;
      case 'all':
      default:
        setFilteredExpiries(data);
        break;
    }
  };

  const handleFilterClick = (filterType) => {
    setActiveFilter(filterType);
    applyFilter(filterType);
  };

  const clearFilter = () => {
    setActiveFilter('all');
    setFilteredExpiries(expiries);
  };

  const handleTrigger = async () => {
    try {
      const res = await triggerExpiryNotifications();
      toast.success(res.data?.message || 'Notifications triggered successfully!', {
        position: 'top-right',
        autoClose: 3000
      });
    } catch (err) {
      toast.error('Failed to trigger notifications', {
        position: 'top-right',
        autoClose: 3000
      });
    }
  };

  const getStatusBadge = (daysLeft) => {
    const days = Number(daysLeft);
    
    // EXPIRED: Days <= 0 (Today and all past dates)
    if (days <= 0) {
      return <Badge bg="danger" className="px-3 py-2">Expired</Badge>;
    } 
    // CRITICAL: Days 1-5
    else if (days >= 1 && days <= 5) {
      return <Badge bg="danger" className="px-3 py-2">Critical - {days} days</Badge>;
    } 
    // WARNING: Days 6-15
    else if (days >= 6 && days <= 15) {
      return <Badge bg="warning" className="px-3 py-2">Warning - {days} days</Badge>;
    } 
    // NOTICE: Days 16-30
    else if (days >= 16 && days <= 30) {
      return <Badge bg="info" className="px-3 py-2">Notice - {days} days</Badge>;
    } 
    // VALID: Days > 30
    else {
      return <Badge bg="success" className="px-3 py-2">Valid - {days} days</Badge>;
    }
  };

  return (
    <div className="expiry-dashboard">
      {/* Header Card */}
      <Card className="mb-4 border-0 shadow-sm">
        <Card.Header className="bg-gradient-primary text-white">
          <div className="d-flex justify-content-between align-items-center">
            <div>
              <h3 className="mb-1">
                <Clock className="me-2" size={28} />
                Expiry Tracking System
              </h3>
              <p className="mb-0 opacity-75">Monitor and manage document expiry dates with automated alerts</p>
            </div>
            <div>
              <Button 
                variant="light" 
                size="sm" 
                onClick={load} 
                className="me-2"
                disabled={loading}
              >
                <RefreshCw size={16} className={loading ? 'spin' : ''} />
              </Button>
            </div>
          </div>
        </Card.Header>
      </Card>

      {/* Statistics Cards - Clickable Filters */}
      <Row className="mb-4">
        <Col md={3}>
          <Card 
            className={`stats-card border-0 shadow-sm h-100 clickable-card ${activeFilter === 'expired' ? 'active-filter-card' : ''}`}
            onClick={() => handleFilterClick('expired')}
            style={{ cursor: 'pointer' }}
            title="Click to view expired documents (Days ≤ 0)"
          >
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">EXPIRED</div>
                  <h2 className="mb-0 text-danger fw-bold">{stats.expired}</h2>
                </div>
                <div className="stats-icon bg-danger">
                  <AlertCircle size={24} />
                </div>
              </div>
              <div className="mt-2">
                <small className="text-danger">
                  <TrendingUp size={12} className="me-1" />
                  Today & past dates
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card 
            className={`stats-card border-0 shadow-sm h-100 clickable-card ${activeFilter === 'expiring5' ? 'active-filter-card' : ''}`}
            onClick={() => handleFilterClick('expiring5')}
            style={{ cursor: 'pointer' }}
            title="Click to view documents expiring in 1-5 days"
          >
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">EXPIRING (1-5 DAYS)</div>
                  <h2 className="mb-0 text-danger fw-bold">{stats.expiring5Days}</h2>
                </div>
                <div className="stats-icon bg-danger">
                  <Bell size={24} />
                </div>
              </div>
              <div className="mt-2">
                <small className="text-danger">
                  Critical alert window
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card 
            className={`stats-card border-0 shadow-sm h-100 clickable-card ${activeFilter === 'expiring30' ? 'active-filter-card' : ''}`}
            onClick={() => handleFilterClick('expiring30')}
            style={{ cursor: 'pointer' }}
            title="Click to view documents expiring in 6-30 days"
          >
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">EXPIRING (6-30 DAYS)</div>
                  <h2 className="mb-0 text-warning fw-bold">{stats.expiring30Days}</h2>
                </div>
                <div className="stats-icon bg-warning">
                  <Clock size={24} />
                </div>
              </div>
              <div className="mt-2">
                <small className="text-warning">
                  Upcoming renewals
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card 
            className={`stats-card border-0 shadow-sm h-100 clickable-card ${activeFilter === 'all' ? 'active-filter-card' : ''}`}
            onClick={() => handleFilterClick('all')}
            style={{ cursor: 'pointer' }}
            title="Click to view all documents"
          >
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">TOTAL MONITORED</div>
                  <h2 className="mb-0 text-primary fw-bold">{stats.total}</h2>
                </div>
                <div className="stats-icon bg-primary">
                  <CheckCircle size={24} />
                </div>
              </div>
              <div className="mt-2">
                <small className="text-primary">
                  Documents tracked
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Alert Banners */}
      {stats.expired > 0 && (
        <Alert variant="danger" className="mb-4">
          <AlertCircle className="me-2" size={20} />
          <strong>Action Required:</strong> {stats.expired} document(s) have expired (including today and past dates). Please renew immediately.
        </Alert>
      )}

      {stats.expiring5Days > 0 && (
        <Alert variant="warning" className="mb-4">
          <Bell className="me-2" size={20} />
          <strong>Critical Alert:</strong> {stats.expiring5Days} document(s) expiring within 1-5 days. Renewal needed urgently.
        </Alert>
      )}

      {/* Expiry Data Table */}
      <Card className="border-0 shadow-sm">
        <Card.Header className="bg-white border-bottom">
          <div className="d-flex justify-content-between align-items-center">
            <h5 className="mb-0">
              <AlertCircle className="me-2" size={20} />
              Expiry Tracking & Notifications
            </h5>
            {activeFilter !== 'all' && (
              <Button 
                variant="outline-secondary" 
                size="sm"
                onClick={clearFilter}
              >
                <X size={16} className="me-1" />
                Clear Filter
              </Button>
            )}
          </div>
          {activeFilter !== 'all' && (
            <div className="mt-3">
              <Badge bg="info" className="px-3 py-2">
                <Filter size={14} className="me-1" />
                Showing: {
                  activeFilter === 'expired' ? 'Expired Documents (Days ≤ 0 - Today & Past Dates)' :
                  activeFilter === 'expiring5' ? 'Documents Expiring in 1-5 Days' :
                  activeFilter === 'expiring30' ? 'Documents Expiring in 6-30 Days' :
                  'All Documents'
                } ({filteredExpiries.length})
              </Badge>
            </div>
          )}
        </Card.Header>
        <Card.Body>
          {loading ? (
            <div className="text-center py-5">
              <div className="spinner-border text-primary" role="status">
                <span className="visually-hidden">Loading...</span>
              </div>
              <p className="mt-3 text-muted">Loading expiry data...</p>
            </div>
          ) : (
            <div className="table-responsive">
              <Table hover className="expiry-table">
                <thead>
                  <tr>
                    <th>Document</th>
                    <th>Employee</th>
                    <th>Type</th>
                    <th>Expiry Date</th>
                    <th>Days Left</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredExpiries.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="text-center text-muted py-5">
                        <CheckCircle size={48} className="text-success mb-3" />
                        <p className="mb-0">
                          {activeFilter === 'all' 
                            ? 'No documents expiring in the configured notification window'
                            : activeFilter === 'expired'
                            ? 'No expired documents found'
                            : 'No documents match the selected filter'
                          }
                        </p>
                        <small className="text-muted">
                          {activeFilter === 'all'
                            ? 'All documents are valid or outside alert range'
                            : activeFilter === 'expired'
                            ? 'All documents are valid (no documents with expiry date ≤ today)'
                            : 'Try selecting a different filter option'
                          }
                        </small>
                      </td>
                    </tr>
                  ) : (
                    filteredExpiries.map(e => {
                      const days = Number(e.daysLeft);
                      return (
                        <tr key={e.id} className={days <= 0 ? 'table-danger' : days <= 5 ? 'table-warning' : ''}>
                          <td>
                            <div>
                              <strong>{e.docId}</strong>
                              <br />
                              <small className="text-muted">{e.fileName}</small>
                            </div>
                          </td>
                          <td>
                            <div>
                              {e.employeeName}
                              <br />
                              <small className="text-muted">{e.employeeId}</small>
                            </div>
                          </td>
                          <td>{e.documentType}</td>
                          <td>
                            <strong>{e.expiryDate}</strong>
                          </td>
                          <td>
                            <span className={
                              days <= 0 ? 'text-danger fw-bold' : 
                              days <= 5 ? 'text-danger fw-bold' : 
                              days <= 15 ? 'text-warning fw-bold' : 
                              'text-success'
                            }>
                              {days <= 0 
                                ? (days === 0 ? 'Expires Today' : `${Math.abs(days)} days overdue`) 
                                : `${days} days`
                              }
                            </span>
                          </td>
                          <td>{getStatusBadge(e.daysLeft)}</td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </Table>
            </div>
          )}
        </Card.Body>
      </Card>
    </div>
  );
};

export default ExpiryDashboard;
